me, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店地理位置非常好，环境优美，国庆节活动丰富多彩。酒店本身很有历史文化底蕴，建议', '酒店地理位置非常好，环境优美，国庆节活动丰富多彩。酒店本身很有历史文化底蕴，建议可以体验酒店介绍的26个打卡点，特别感谢小梁的细致周到讲解，下次还会选择这里。', '2024-10-02', 5, '[''整体满意度'', ''周边配套'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236g12000fxdd08g042E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234i12000fxe89vc52A6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233212000fxauz2d8C46_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次选择了历史悠久的花园酒店 ', '这次选择了历史悠久的花园酒店 
